    76→                  <PricingPage />
    77→                </AppLayout>
    78→              }
    79→            />
    80→            <Route
    81→              path="/real-time-data"
    82→              element={
    83→                <AppLayout>
    84→                  <RealTimeDataPage />
    85→                </AppLayout>
    86→              }
    87→            />
    88→
    89→            {/* Protected routes */}
    90→            <Route
    91→              path="/dashboard"
    92→              element={
    93→                <ProtectedRoute>
    94→                  <AppLayout>
    95→                    <Dashboard />
    96→                  </AppLayout>
    97→                </ProtectedRoute>
    98→              }
    99→            />
   100→            <Route
   101→              path="/category/:categoryId"
   102→              element={
   103→                <ProtectedRoute>
   104→                  <AppLayout hideFooter>
   105→                    <CategoryPage />
   106→                  </AppLayout>
   107→                </ProtectedRoute>
   108→              }
   109→            />
   110→            <Route
   111→              path="/settings"
   112→              element={
   113→                <ProtectedRoute>
   114→                  <AppLayout>
   115→                    <SettingsPage />
   116→                  </AppLayout>
   117→                </ProtectedRoute>
   118→              }
   119→            />
   120→            <Route
   121→              path="/history"
   122→              element={
   123→                <ProtectedRoute>
   124→                  <AppLayout>
   125→                    <HistoryPage />
   126→                  </AppLayout>
   127→                </ProtectedRoute>
   128→              }
   129→            />
   130→
   131→            {/* Legal pages */}
   132→            <Route path="/privacy-policy" element={<AppLayout><PrivacyPolicy /></AppLayout>} />
   133→            <Route path="/terms-of-service" element={<AppLayout><TermsOfService /></AppLayout>} />
   134→            <Route path="/cookie-policy" element={<AppLayout><CookiePolicy /></AppLayout>} />
   135→
   136→            {/* Catch all */}
   137→            <Route path="*" element={<Navigate to="/" replace />} />
   138→          </Routes>
   139→        </SubscriptionProvider>
   140→      </AuthProvider>
   141→    </Router>
   142→  );
   143→}
