    16→const oauthRoutes = require("./routes/oauth");
    17→const instagramWebhook = require("./routes/instagramWebhook");
    18→
    19→
    20→const app = express();
    21→app.set('trust proxy', 1); // Required for Render (proxy) — fixes express-rate-limit X-Forwarded-For error
    22→const PORT = process.env.PORT || 5000;
    23→
    24→
    25→/* ===============================
    26→   🔥 CORS CONFIG (PRODUCTION READY)
    27→================================ */
    28→
    29→const allowedOrigins = [
    30→  "http://localhost:3000",
    31→  "http://127.0.0.1:3000",
    32→  "https://gormaran-growth-hub-1.onrender.com", // frontend
    33→  "https://gormaran-growth-hub.onrender.com",   // backend
    34→  "https://gormaran.io",
    35→  "https://www.gormaran.io",
    36→];
    37→
    38→app.use(
    39→  cors({
    40→    origin: function (origin, callback) {
    41→      if (!origin) return callback(null, true);
    42→
    43→      if (allowedOrigins.includes(origin)) {
    44→        callback(null, true);
    45→      } else {
    46→        callback(new Error("Not allowed by CORS"));
    47→      }
    48→    },
    49→    credentials: true,
    50→  })
    51→);
    52→
    53→
    54→
    55→/* ===============================
    56→   🔥 BODY PARSING
    57→================================ */
    58→
    59→// Stripe webhook necesita raw body
    60→app.use("/api/stripe/webhook", express.raw({ type: "application/json" }));
    61→
    62→app.use(express.json({ limit: "10mb" }));
    63→app.use(express.urlencoded({ extended: true }));
    64→
    65→/* ===============================
    66→   🔥 HEALTH CHECK
    67→================================ */
    68→app.get("/health", (req, res) => {
    69→  res.json({
    70→    status: "ok",
    71→    timestamp: new Date().toISOString(),
    72→    env: {
    73→      anthropic: !!process.env.ANTHROPIC_API_KEY,
    74→      stripe: !!process.env.STRIPE_SECRET_KEY,
    75→      firebase: !!process.env.FIREBASE_SERVICE_ACCOUNT,
    76→    },
    77→  });
    78→});
    79→
    80→/* ===============================
    81→   🔥 ROUTES
    82→================================ */
    83→app.use("/api/ai", aiRoutes);
    84→app.use("/api/stripe", stripeRoutes);
    85→app.use("/api/image", imageRoutes);
    86→app.use("/api/oauth", oauthRoutes);
    87→app.use("/api/webhooks/instagram", instagramWebhook);
    88→
    89→/* ===============================
    90→   🔥 404
    91→================================ */
    92→app.use((req, res) => {
    93→  res.status(404).json({
    94→    error: `Route ${req.method} ${req.url} not found`,
    95→  });
    96→});
    97→
    98→/* ===============================
    99→   🔥 ERROR HANDLER
   100→================================ */
   101→app.use((err, req, res, next) => {
   102→  console.error("[Server Error]", err.message);
   103→  res.status(err.status || 500).json({
   104→    error:
   105→      process.env.NODE_ENV === "production"
   106→        ? "Internal server error"
   107→        : err.message,
   108→  });
   109→});
   110→
   111→/* ===============================
   112→   🔥 START SERVER
   113→================================ */
   114→app.listen(PORT, () => {
   115→  console.log(`\n🚀 Gormaran AI Growth Hub Server`);
   116→  console.log(`   Running on port: ${PORT}`);
   117→  console.log(`   Health: /health\n`);
   118→});
   119→
   120→module.exports = app;

