     1→import React, { createContext, useContext, useEffect, useState } from 'react';
     2→import {
     3→  createUserWithEmailAndPassword,
     4→  signInWithEmailAndPassword,
     5→  signOut,
     6→  onAuthStateChanged,
     7→  signInWithPopup,
     8→  updateProfile,
     9→  sendPasswordResetEmail,
    10→} from 'firebase/auth';
    11→import { doc, setDoc, getDoc, serverTimestamp } from 'firebase/firestore';
    12→import { auth, db, googleProvider } from '../firebase/config';
    13→
    14→const AuthContext = createContext(null);
    15→
    16→export function useAuth() {
    17→  return useContext(AuthContext);
    18→}
    19→
    20→export function AuthProvider({ children }) {
    21→  const [currentUser, setCurrentUser] = useState(null);
    22→  const [userProfile, setUserProfile] = useState(null);
    23→  const [loading, setLoading] = useState(true);
    24→
    25→  async function createUserProfile(user, displayName) {
    26→    const userRef = doc(db, 'users', user.uid);
    27→    const snap = await getDoc(userRef);
    28→    if (!snap.exists()) {
    29→      await setDoc(userRef, {
    30→        uid: user.uid,
    31→        email: user.email,
    32→        displayName: displayName || user.displayName || '',
    33→        photoURL: user.photoURL || '',
    34→        subscription: 'free',
    35→        usageCount: 0,
    36→        usageResetDate: new Date(),
    37→        createdAt: serverTimestamp(),
    38→        updatedAt: serverTimestamp(),
    39→      });
    40→    }
    41→    const updated = await getDoc(userRef);
    42→    setUserProfile(updated.data());
    43→  }
    44→
    45→  async function register(email, password, displayName) {
    46→    const { user } = await createUserWithEmailAndPassword(auth, email, password);
    47→    await updateProfile(user, { displayName });
    48→    await createUserProfile(user, displayName);
    49→    return user;
    50→  }
    51→
    52→  async function login(email, password) {
    53→    const result = await signInWithEmailAndPassword(auth, email, password);
    54→    await refreshUserProfile(result.user.uid);
    55→    return result;
    56→  }
    57→
    58→  async function signInWithGoogle() {
    59→    const result = await signInWithPopup(auth, googleProvider);
    60→    await createUserProfile(result.user);
    61→    return result;
    62→  }
    63→
    64→  async function logout() {
    65→    setUserProfile(null);
    66→    return signOut(auth);
    67→  }
    68→
    69→  async function resetPassword(email) {
    70→    return sendPasswordResetEmail(auth, email);
    71→  }
    72→
    73→  async function refreshUserProfile(uid) {
    74→    const userRef = doc(db, 'users', uid || currentUser?.uid);
    75→    const snap = await getDoc(userRef);
    76→    if (snap.exists()) {
    77→      setUserProfile(snap.data());
    78→      return snap.data();
    79→    }
    80→    return null;
    81→  }
    82→
    83→  useEffect(() => {
    84→    const unsubscribe = onAuthStateChanged(auth, async (user) => {
    85→      setCurrentUser(user);
    86→      if (user) {
    87→        await createUserProfile(user);
    88→      } else {
    89→        setUserProfile(null);
    90→      }
    91→      setLoading(false);
    92→    });
    93→    return unsubscribe;
    94→  }, []);
    95→
    96→  const value = {
    97→    currentUser,
    98→    userProfile,
    99→    loading,
   100→    register,
   101→    login,
   102→    logout,
   103→    signInWithGoogle,
   104→    resetPassword,
   105→    refreshUserProfile,
   106→  };
   107→
   108→  return (
   109→    <AuthContext.Provider value={value}>
   110→      {!loading && children}
   111→    </AuthContext.Provider>
   112→  );
   113→}
